// Validate incoming payload
const body = $input.first().json.body || $input.first().json;

const required = ['user_id', 'artifact_type', 'channel'];
for (const field of required) {
  if (!body[field]) {
    throw new Error(`Missing required field: ${field}`);
  }
}

// Normalize
return [{
  json: {
    user_id: body.user_id,
    artifact_type: body.artifact_type,
    artifact_id: body.artifact_id || null,
    competitor_name: body.competitor_name || null,
    channel: body.channel,
    recipient_team: body.recipient_team || null,
    recipient_ids: body.recipient_ids || null,
    deal_id: body.deal_id || null,
    content_md: body.content_md || '',
    content_title: body.content_title || `${body.artifact_type} update`,
    metadata: body.metadata || {}
  }
}];

const data = $('Validate & Normalize').first().json;
const webhookUrl = $('Get Slack Config').first().json.incoming_webhook_url;

// Build Slack Block Kit message
const artifactLabels = {
  battlecard: ':shield: Battlecard',
  objection_library: ':speech_balloon: Objection Library',
  swipe_file: ':page_facing_up: Swipe File',
  maturity_model: ':bar_chart: Maturity Model',
  deal_brief: ':briefcase: Deal Brief',
  scorecard: ':chart_with_upwards_trend: Scorecard'
};

const label = artifactLabels[data.artifact_type] || data.artifact_type;
const title = data.content_title;
const competitor = data.competitor_name ? ` — ${data.competitor_name}` : '';

const blocks = [
  {
    type: 'header',
    text: { type: 'plain_text', text: `${title}${competitor}`, emoji: true }
  },
  {
    type: 'section',
    text: { type: 'mrkdwn', text: `*Type:* ${label}\n*Delivered:* ${new Date().toLocaleDateString('en-US', { weekday: 'short', month: 'short', day: 'numeric' })}` }
  }
];

// Add content preview if available (truncated)
if (data.content_md) {
  const preview = data.content_md.length > 500 
    ? data.content_md.substring(0, 500) + '…'
    : data.content_md;
  blocks.push({
    type: 'section',
    text: { type: 'mrkdwn', text: preview }
  });
}

// Add feedback CTA
blocks.push(
  { type: 'divider' },
  {
    type: 'context',
    elements: [{ type: 'mrkdwn', text: ':star: _Rate this artifact in Signal Plane to help improve future content_' }]
  }
);

return [{
  json: {
    webhook_url: webhookUrl,
    payload: { blocks, text: `New ${label} delivered${competitor}` }
  }
}];
